5	
6	//! Warp-level matrix dialect operations.
7	
8	use pliron::{
9	    builtin::op_interfaces::{NOpdsInterface, NResultsInterface},
10	    builtin::types::{FP32Type, FP64Type, IntegerType},
11	    common_traits::Verify,
12	    context::Context,
13	    context::Ptr,
14	    location::Located,
15	    op::Op,
16	    operation::Operation,
17	    result::Error,
18	    r#type::Typed,
19	    verify_err,
20	};
21	use pliron_derive::pliron_op;
22	
23	/// In-register 8×8 matrix transpose (movmatrix.sync.aligned.m8n8.trans.b16).
24	#[pliron_op(
25	    name = "nvvm.movmatrix_trans_b16",
26	    format,
27	    interfaces = [NOpdsInterface<1>, NResultsInterface<1>],
28	)]
29	pub struct MovmatrixTransB16Op;
30	
31	impl MovmatrixTransB16Op {
32	    /// Wrap an existing operation pointer.
33	    pub fn new(op: Ptr<Operation>) -> Self {
34	        Self { op }
35	    }
36	}
37	
38	impl Verify for MovmatrixTransB16Op {
39	    fn verify(&self, ctx: &Context) -> Result<(), Error> {
40	        let op = self.get_operation().deref(ctx);
41	
42	        if op.operands().count() != 1 || op.get_num_results() != 1 {
43	            return verify_err!(
44	                op.loc(),
45	                "nvvm.movmatrix_trans_b16 requires one operand and one result"
46	            );
47	        }
48	
49	        for (name, ty) in [
50	            ("operand", op.get_operand(0).get_type(ctx)),
51	            ("result", op.get_result(0).get_type(ctx)),
52	        ] {
53	            let ty_ref = ty.deref(ctx);
54	            let Some(integer) = ty_ref.downcast_ref::<IntegerType>() else {
55	                return verify_err!(
56	                    op.loc(),
57	                    "nvvm.movmatrix_trans_b16 {} must be a 32-bit integer",
58	                    name
59	                );
60	            };
61	            if integer.width() != 32 {
62	                return verify_err!(
63	                    op.loc(),
64	                    "nvvm.movmatrix_trans_b16 {} must be a 32-bit integer",
65	                    name
66	                );
67	            }
68	        }
69	
70	        Ok(())
71	    }
72	}
73	
74	/// Register-only warp MMA: m16n8k16 with f32 accumulator and bf16 inputs.
75	///
76	/// # Operands
77	///
78	/// - operands 0-3: four f32 C accumulator registers
79	/// - operands 4-7: four i32 A fragment registers, each packing two BF16 values
80	/// - operands 8-9: two i32 B fragment registers, each packing two BF16 values
81	///
82	/// # Results
83	///
84	/// - results 0-3: four f32 D accumulator registers
85	#[pliron_op(
86	    name = "nvvm.mma_m16n8k16_f32_bf16",
87	    format,
88	    interfaces = [NOpdsInterface<10>, NResultsInterface<4>],
89	)]
90	pub struct MmaM16N8K16F32Bf16Op;
91	
92	impl Verify for MmaM16N8K16F32Bf16Op {
93	    fn verify(&self, ctx: &Context) -> Result<(), Error> {
94	        let op = self.get_operation().deref(ctx);
95	        let operands: Vec<_> = op.operands().collect();
96	
97	        if operands.len() != 10 {
98	            return verify_err!(
99	                op.loc(),
100	                "nvvm.mma_m16n8k16_f32_bf16 requires 10 register operands, got {}",
101	                operands.len()
102	            );
103	        }
104	
105	        for (index, operand) in operands.iter().take(4).enumerate() {
106	            let ty = operand.get_type(ctx);
107	            if ty.deref(ctx).downcast_ref::<FP32Type>().is_none() {
108	                return verify_err!(
109	                    op.loc(),
110	                    "nvvm.mma_m16n8k16_f32_bf16 C operand {} must be f32",
111	                    index
112	                );
113	            }
114	        }
115	
116	        for (index, operand) in operands.iter().enumerate().skip(4) {
117	            let ty = operand.get_type(ctx);
118	            let ty = ty.deref(ctx);
119	            let Some(integer) = ty.downcast_ref::<IntegerType>() else {
120	                return verify_err!(
121	                    op.loc(),
122	                    "nvvm.mma_m16n8k16_f32_bf16 packed operand {} must be i32",
123	                    index
124	                );
125	            };
126	            if integer.width() != 32 {
127	                return verify_err!(
128	                    op.loc(),
129	                    "nvvm.mma_m16n8k16_f32_bf16 packed operand {} must be i32",
130	                    index
131	                );
132	            }
133	        }
134	
135	        if op.get_num_results() != 4 {
136	            return verify_err!(
137	                op.loc(),
138	                "nvvm.mma_m16n8k16_f32_bf16 requires 4 f32 results"
139	            );
140	        }
141	
142	        for index in 0..4 {
143	            let ty = op.get_result(index).get_type(ctx);
144	            if ty.deref(ctx).downcast_ref::<FP32Type>().is_none() {
145	                return verify_err!(
146	                    op.loc(),
147	                    "nvvm.mma_m16n8k16_f32_bf16 result {} must be f32",
148	                    index
149	                );
150	            }
151	        }
152	
153	        Ok(())
154	    }
155	}
156	
157	impl MmaM16N8K16F32Bf16Op {
158	    /// Wrap an existing operation pointer.
159	    pub fn new(op: Ptr<Operation>) -> Self {
160	        MmaM16N8K16F32Bf16Op { op }
161	    }
162	}
163	
164	/// Register-only warp MMA: m16n8k16 with f32 accumulator and f16 inputs.
165	///
166	/// # Operands
167	///
168	/// - operands 0-3: four f32 C accumulator registers
169	/// - operands 4-7: four i32 A fragment registers, each packing two F16 values
170	/// - operands 8-9: two i32 B fragment registers, each packing two F16 values
171	///
172	/// # Results
173	///
