//! Warp-level matrix dialect operations.

use pliron::{
    builtin::op_interfaces::{NOpdsInterface, NResultsInterface},
    builtin::types::{FP32Type, FP64Type, IntegerType},
    common_traits::Verify,
    context::Context,
